import{bQ as a,aL as e,u as d,G as r}from"./chunks/framework.D06dwy5q.js";const l=JSON.parse('{"title":"观测和发布","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/12-观测和发布.md","filePath":"00.互联网与架构基础/12-观测和发布.md","lastUpdated":null}'),i={name:"00.互联网与架构基础/12-观测和发布.md"};function p(E,t,o,A,h,s){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="观测和发布" tabindex="-1">观测和发布 <a class="header-anchor" href="#观测和发布" aria-label="Permalink to &quot;观测和发布&quot;">​</a></h1><p>系统跑起来以后，还会有两个很现实的问题：出问题时能不能看见，改代码时能不能稳稳发出去。</p><p>看不见，故障现场只能猜。发不稳，一个小改动也可能变成线上事故。日志、指标、链路追踪、告警、CI/CD、灰度和回滚，都是围绕这两件事出现的。</p><h2 id="一、看见系统" tabindex="-1">一、看见系统 <a class="header-anchor" href="#一、看见系统" aria-label="Permalink to &quot;一、看见系统&quot;">​</a></h2><p>系统不是只要进程还在就算正常。用户可能已经打不开页面，接口可能开始变慢，数据库连接可能快打满，某个服务可能在不停重启。</p><p>常见可观测信号有四类：</p><table tabindex="0"><thead><tr><th>信号</th><th>记录什么</th><th>常见用途</th></tr></thead><tbody><tr><td>Metrics</td><td>数值指标</td><td>QPS、延迟、错误率、CPU、内存</td></tr><tr><td>Logs</td><td>离散日志</td><td>错误堆栈、请求记录、业务状态</td></tr><tr><td>Traces</td><td>调用链</td><td>一次请求经过哪些服务、每段耗时</td></tr><tr><td>Events</td><td>事件</td><td>Pod 重启、调度失败、告警触发、发布记录</td></tr></tbody></table><p>指标适合看趋势和告警，日志适合看细节，链路追踪适合看跨服务调用，事件适合看状态变化。单独看一种，经常只能看到一部分。</p><h2 id="二、指标" tabindex="-1">二、指标 <a class="header-anchor" href="#二、指标" aria-label="Permalink to &quot;二、指标&quot;">​</a></h2><p>指标把系统状态变成随时间变化的数值。比如 CPU 使用率、HTTP 500 数量、接口 P95 延迟、数据库连接数。</p><p>常见服务指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>请求量</td><td>当前有多少流量</td></tr><tr><td>错误率</td><td>失败请求占比</td></tr><tr><td>延迟</td><td>请求处理耗时</td></tr><tr><td>饱和度</td><td>CPU、内存、连接池、线程池是否接近上限</td></tr></tbody></table><p>接口变慢时，如果请求量突然上涨、P95 延迟上涨、错误率也上涨，可能是服务过载。请求量没变但数据库慢查询增加，则更接近数据库或 SQL 问题。</p><h2 id="三、日志" tabindex="-1">三、日志 <a class="header-anchor" href="#三、日志" aria-label="Permalink to &quot;三、日志&quot;">​</a></h2><p>日志记录具体发生过什么。应用日志里常见请求路径、状态码、耗时、用户 ID、trace id、错误堆栈。入口层日志里能看到客户端 IP、Host、upstream 状态和转发耗时。</p><p>日志要能串起来。一次请求经过 Nginx、网关、后端服务和数据库时，如果每一层都有同一个 trace id，排查会清楚很多。没有 trace id 时，只能靠时间范围、用户 ID、请求路径和状态码拼线索。</p><p>一条有用的接口错误日志通常至少包含：请求路径、方法、状态码、耗时、错误类型、trace id。只写一句 <code>error occurred</code>，现场很难判断发生了什么。</p><h2 id="四、链路追踪" tabindex="-1">四、链路追踪 <a class="header-anchor" href="#四、链路追踪" aria-label="Permalink to &quot;四、链路追踪&quot;">​</a></h2><p>微服务拆开以后，一次请求可能经过很多服务。链路追踪用 Trace 和 Span 记录一次请求的完整路径。</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20participant%20User%20as%20%E7%94%A8%E6%88%B7%E8%AF%B7%E6%B1%82%0A%20%20participant%20Gateway%20as%20%E7%BD%91%E5%85%B3%0A%20%20participant%20Order%20as%20%E8%AE%A2%E5%8D%95%E6%9C%8D%E5%8A%A1%0A%20%20participant%20UserSvc%20as%20%E7%94%A8%E6%88%B7%E6%9C%8D%E5%8A%A1%0A%20%20participant%20DB%20as%20%E6%95%B0%E6%8D%AE%E5%BA%93%0A%0A%20%20User-%3E%3EGateway%3A%20Trace%20A%0A%20%20Gateway-%3E%3EOrder%3A%20Span%201%0A%20%20Order-%3E%3EUserSvc%3A%20Span%202%0A%20%20Order-%3E%3EDB%3A%20Span%203%0A"></div><p>如果下单接口 3 秒才返回，链路追踪能看到这 3 秒耗在网关、订单服务、用户服务还是数据库。它解决的是跨服务调用看不完整的问题。</p><h2 id="五、发布" tabindex="-1">五、发布 <a class="header-anchor" href="#五、发布" aria-label="Permalink to &quot;五、发布&quot;">​</a></h2><p>发布就是把新代码、新配置、新镜像变成线上状态。早期发布可能是手工复制文件和重启进程，后来逐渐变成 CI/CD、镜像构建、自动部署、灰度和回滚。</p><p>常见发布链路：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Git%5B%22%E4%BB%A3%E7%A0%81%E6%8F%90%E4%BA%A4%22%5D%0A%20%20CI%5B%22CI%20%E6%9E%84%E5%BB%BA%E5%92%8C%E6%B5%8B%E8%AF%95%22%5D%0A%20%20Image%5B%22%E6%9E%84%E5%BB%BA%E9%95%9C%E5%83%8F%22%5D%0A%20%20Registry%5B%22%E9%95%9C%E5%83%8F%E4%BB%93%E5%BA%93%22%5D%0A%20%20Deploy%5B%22%E9%83%A8%E7%BD%B2%E7%B3%BB%E7%BB%9F%22%5D%0A%20%20Runtime%5B%22%E6%9C%8D%E5%8A%A1%E5%99%A8%20%2F%20Kubernetes%22%5D%0A%20%20Observe%5B%22%E7%9B%91%E6%8E%A7%E8%A7%82%E5%AF%9F%22%5D%0A%0A%20%20Git%20--%3E%20CI%0A%20%20CI%20--%3E%20Image%0A%20%20Image%20--%3E%20Registry%0A%20%20Registry%20--%3E%20Deploy%0A%20%20Deploy%20--%3E%20Runtime%0A%20%20Runtime%20--%3E%20Observe%0A"></div><p>发布系统要留下记录：谁发的，发了哪个版本，改了哪些配置，影响哪些服务，出了问题怎么回到上一版。</p><h2 id="六、灰度和回滚" tabindex="-1">六、灰度和回滚 <a class="header-anchor" href="#六、灰度和回滚" aria-label="Permalink to &quot;六、灰度和回滚&quot;">​</a></h2><p>灰度发布让新版本先接一小部分流量。观察错误率、延迟、业务指标正常后，再扩大流量。回滚则是在新版本出问题时，把流量或版本切回旧状态。</p><p>常见灰度方式：</p><table tabindex="0"><thead><tr><th>做法</th><th>说明</th></tr></thead><tbody><tr><td>按比例</td><td>5%、20%、50%、100% 逐步放量</td></tr><tr><td>按用户</td><td>内部账号或指定用户先使用</td></tr><tr><td>按地域</td><td>某个区域先切新版本</td></tr><tr><td>按实例</td><td>先替换少量实例</td></tr></tbody></table><p>回滚要看镜像版本，也要看数据库结构、配置、缓存、消息队列里的数据是否被新版本影响。涉及数据结构变更时，发布和回滚要提前想清楚兼容关系。</p><p>可观测性和发布是一起工作的。没有观测，发布后不知道是否正常；没有稳定发布，问题修好也很难安全上线。</p>',32)])])}const c=a(i,[["render",p]]);export{l as __pageData,c as default};
